#include "kernel_operator.h"
#include "ca6k_01126_custom_tiling.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k01126Custom {
public:
    __aicore__ inline KernelCa6k01126Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                int32_t numFeatures, uint32_t spatialSize,
                                float eps)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        numFeatures_ = numFeatures;
        spatialSize_ = spatialSize;
        eps_ = eps;
        batchSize_ = totalLen_ / (numFeatures_ * spatialSize_);

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        if (blockIdx >= batchSize_ * static_cast<uint32_t>(numFeatures_)) return;

        uint32_t n = blockIdx / static_cast<uint32_t>(numFeatures_);
        uint32_t c = blockIdx % static_cast<uint32_t>(numFeatures_);
        uint32_t baseOffset = (n * static_cast<uint32_t>(numFeatures_) + c) * spatialSize_;

        float sum = 0.0f;
        float sumSq = 0.0f;
        uint32_t remaining = spatialSize_;
        uint32_t offset = 0;
        while (remaining > 0) {
            uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[baseOffset + offset], curLen);
            inQueueX_.EnQue(xLocal);

            xLocal = inQueueX_.DeQue<float>();
            for (uint32_t i = 0; i < curLen; i++) {
                float val = xLocal.GetValue(i);
                sum += val;
                sumSq += val * val;
            }
            inQueueX_.FreeTensor(xLocal);

            offset += curLen;
            remaining -= curLen;
        }

        float mean = sum / static_cast<float>(spatialSize_);
        float var = sumSq / static_cast<float>(spatialSize_) - mean * mean;
        if (var < 0.0f) var = 0.0f;
        float invStd = 1.0f / sqrtf(var + eps_);

        remaining = spatialSize_;
        offset = 0;
        while (remaining > 0) {
            uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[baseOffset + offset], curLen);
            inQueueX_.EnQue(xLocal);

            xLocal = inQueueX_.DeQue<float>();
            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            for (uint32_t i = 0; i < curLen; i++) {
                float val = xLocal.GetValue(i);
                float yVal = (val - mean) * invStd;
                yLocal.SetValue(i, yVal);
            }
            AscendC::DataCopy(yGm_[baseOffset + offset], yLocal, curLen);
            outQueueY_.FreeTensor(yLocal);
            inQueueX_.FreeTensor(xLocal);

            offset += curLen;
            remaining -= curLen;
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    int32_t numFeatures_ {0};
    uint32_t spatialSize_ {0};
    uint32_t batchSize_ {0};
    float eps_ {1e-5f};
};

extern "C" __global__ __aicore__ void ca6k_01126_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k01126Custom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength,
            tiling_data.numFeatures, tiling_data.spatialSize, tiling_data.eps);
    op.Process();
}
